import { Global, css } from '@emotion/react';
import React, { forwardRef, useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react';
import { ResizableBox } from 'react-resizable';

import { CollapseButton } from './CollapseButton';
import { ResizablePanelHandle } from './ResizablePanelHandle';
import { COMPACT_CONTENT_Z_INDEX, DEFAULT_WIDTH, EDGE_COLLAPSE_BTN_CLASS } from './constants';
import { ContentContext, SidebarContext } from './contexts';
import type {
  ContentProps,
  NavButtonProps,
  NavProps,
  PanelBodyProps,
  PanelHeaderButtonProps,
  PanelHeaderProps,
  PanelHeaderTitleProps,
  PanelProps,
  SidebarProps,
} from './types';
import { useSidebarCollapse } from './useSidebarCollapse';
import { getContentAnimation } from './utils';
import { Button } from '../Button';
import { useDesignSystemTheme } from '../Hooks/useDesignSystemTheme';
import { CloseIcon } from '../Icon';
import { Typography } from '../Typography';
import { importantify } from '../utils/css-utils';
import { addDebugOutlineIfEnabled } from '../utils/debug';
import { useMediaQuery } from '../utils/useMediaQuery';

export function Nav({ children, dangerouslyAppendEmotionCSS }: NavProps): JSX.Element {
  const { theme } = useDesignSystemTheme();
  return (
    <nav
      css={[
        {
          display: 'flex',
          flexDirection: 'column',
          gap: theme.spacing.xs,
          padding: theme.spacing.xs,
        },
        dangerouslyAppendEmotionCSS,
      ]}
    >
      {children}
    </nav>
  );
}

export const NavButton = React.forwardRef<HTMLButtonElement, NavButtonProps>(
  // eslint-disable-next-line react-component-name/react-component-name -- TODO(FEINF-4716)
  (
    { active, disabled, icon, onClick, children, dangerouslyAppendEmotionCSS, 'aria-label': ariaLabel, ...restProps },
    ref,
  ) => {
    const { theme } = useDesignSystemTheme();
    return (
      <div
        css={[
          active
            ? importantify({
                borderRadius: theme.borders.borderRadiusSm,
                background: theme.colors.actionDefaultBackgroundPress,
                button: {
                  '&:enabled:not(:hover):not(:active) > .anticon': { color: theme.colors.actionTertiaryTextPress },
                },
              })
            : undefined,
          dangerouslyAppendEmotionCSS,
        ]}
      >
        <Button ref={ref} icon={icon} onClick={onClick} disabled={disabled} aria-label={ariaLabel} {...restProps}>
          {children}
        </Button>
      </div>
    );
  },
);

// ---------------------------------------------------------------------------
// Content
// ---------------------------------------------------------------------------

export const Content = forwardRef<HTMLDivElement, ContentProps>(function Content(
  {
    disableResize,
    openPanelId,
    closable = true,
    onClose,
    onResizeStart,
    onResizeStop,
    width,
    minWidth,
    maxWidth,
    destroyInactivePanels = false,
    children,
    dangerouslyAppendEmotionCSS,
    enableCompact,
    resizeBoxStyle,
    noSideBorder,
    hideResizeHandle,
    collapsible = false,
    collapsed: controlledCollapsed,
    onCollapseChange,
    componentId,
  },
  ref,
) {
  const { theme } = useDesignSystemTheme();
  const sidebarContext = useContext(SidebarContext);
  const isRight = sidebarContext.position === 'right';
  const position = sidebarContext.position || 'left';
  const showEdgeCollapse = collapsible;
  const hasCompactToggle = collapsible || !closable;

  // -- Compact mode ----------------------------------------------------------
  const isCompact = useMediaQuery({ query: `not (min-width: ${theme.responsive.breakpoints.sm}px)` }) && enableCompact;

  // -- Expand/collapse state (shared by compact mode and edge collapse) -----

  const { isExpanded, toggleExpanded, setIsExpanded } = useSidebarCollapse({
    collapsed: controlledCollapsed,
    onCollapseChange,
  });

  const expandBtnRef = useRef<HTMLDivElement>(null);
  const collapseBtnRef = useRef<HTMLDivElement>(null);

  const handleCollapseToggle = useCallback(() => {
    toggleExpanded();
    // After React commits the DOM update, move focus to the counterpart button
    requestAnimationFrame(() => {
      if (isExpanded) {
        expandBtnRef.current?.focus();
      } else {
        collapseBtnRef.current?.focus();
      }
    });
  }, [toggleExpanded, isExpanded]);

  useEffect(() => {
    if (hasCompactToggle && enableCompact && !isCompact) {
      setIsExpanded(true);
    }
  }, [isCompact, hasCompactToggle, enableCompact, setIsExpanded]);

  // -- Animation -------------------------------------------------------------
  const defaultAnimation = useMemo(
    () => getContentAnimation(isCompact ? DEFAULT_WIDTH : width || DEFAULT_WIDTH),
    [isCompact, width],
  );
  const isPanelClosed = openPanelId == null;
  const [animation, setAnimation] = useState(isPanelClosed ? defaultAnimation : undefined);

  // -- Drag state ------------------------------------------------------------
  const [dragging, setDragging] = useState(false);

  // -- Stable onClose ref ----------------------------------------------------
  const onCloseRef = useRef(onClose);
  useEffect(() => {
    onCloseRef.current = onClose;
  }, [onClose]);

  // -- Styles ----------------------------------------------------------------
  const compactStyle = css(
    isCompact && {
      position: 'absolute',
      zIndex: COMPACT_CONTENT_Z_INDEX,
      left: isRight ? undefined : closable ? '100%' : undefined,
      right: isRight ? (closable ? '100%' : undefined) : undefined,
      borderRight: !isRight && !noSideBorder ? `1px solid ${theme.colors.border}` : undefined,
      borderLeft: isRight && !noSideBorder ? `1px solid ${theme.colors.border}` : undefined,
      backgroundColor: theme.colors.backgroundPrimary,
      width: DEFAULT_WIDTH,
      top: -1,
    },
  );

  const containerStyle = css({
    animation: animation?.open,
    direction: isRight ? 'rtl' : 'ltr',
    position: 'relative',
    borderWidth: isRight
      ? `0 ${noSideBorder ? 0 : theme.general.borderWidth}px 0 0 `
      : `0 0 0 ${noSideBorder ? 0 : theme.general.borderWidth}px`,
    borderStyle: 'inherit',
    borderColor: 'inherit',
    boxSizing: 'content-box',
  });

  const hiddenPanelStyle = css(isPanelClosed && { display: 'none' });
  const isNotExpandedStyle = css(isCompact && hasCompactToggle && !isExpanded && { display: 'none' });

  const highlightedBorderStyle = isRight
    ? css({ borderLeft: `2px solid ${theme.colors.actionDefaultBorderHover}` })
    : css({ borderRight: `2px solid ${theme.colors.actionDefaultBorderHover}` });

  const alwaysVisibleBtnStyle = css({
    [`.${EDGE_COLLAPSE_BTN_CLASS}`]: { opacity: 1, pointerEvents: 'auto' },
  });

  const btnHighlightStyle = css({
    [`.${EDGE_COLLAPSE_BTN_CLASS}`]: {
      opacity: 1,
      pointerEvents: 'auto',
      boxShadow: `0 0 0 2px ${theme.colors.actionDefaultBorderHover}, 0px 0px 8px rgba(0, 0, 0, 0.33)`,
    },
  });

  const edgeHandleStyle = css({
    height: '100%',
    position: 'relative',
    ...(isRight
      ? { borderLeft: `${theme.general.borderWidth}px solid ${theme.colors.border}` }
      : { borderRight: `${theme.general.borderWidth}px solid ${theme.colors.border}` }),
    '&:hover': [highlightedBorderStyle, btnHighlightStyle],
  });

  const compactToggleStyle = css({
    position: isExpanded ? 'static' : 'relative',
    width: isExpanded ? undefined : theme.spacing.md,
    marginRight: isExpanded ? theme.spacing.md : undefined,
    height: '100%',
  });

  const compactToggleBtnPositioner = isExpanded
    ? css({
        position: 'absolute',
        ...(isRight ? { right: DEFAULT_WIDTH } : { left: DEFAULT_WIDTH }),
        top: 0,
        height: '100%',
        zIndex: COMPACT_CONTENT_Z_INDEX + 1,
      })
    : undefined;

  const resizeHandleStyle = isRight ? { left: 0 } : { right: 0 };

  // -- Context value ---------------------------------------------------------
  const value = useMemo(
    () => ({
      openPanelId,
      closable,
      destroyInactivePanels,
      setIsClosed: () => {
        onCloseRef.current?.();
        if (!animation) {
          setAnimation(defaultAnimation);
        }
      },
    }),
    [openPanelId, closable, defaultAnimation, animation, destroyInactivePanels],
  );

  // -- Render ----------------------------------------------------------------
  return (
    <ContentContext.Provider value={value}>
      {disableResize || isCompact ? (
        <>
          <div
            css={[
              css({ width: width || '100%', height: '100%', overflow: 'hidden' }, containerStyle, compactStyle),
              dangerouslyAppendEmotionCSS,
              hiddenPanelStyle,
              isNotExpandedStyle,
            ]}
            aria-hidden={isPanelClosed}
          >
            <div css={{ opacity: 1, height: '100%', animation: animation?.show, direction: 'ltr' }}>{children}</div>
          </div>
          {hasCompactToggle && isCompact && (
            <div css={compactToggleStyle}>
              <div css={compactToggleBtnPositioner}>
                <CollapseButton
                  componentId={componentId ? `${componentId}.toggle` : 'sidebar-toggle'}
                  visibility="persistent"
                  isExpanded={isExpanded}
                  position={position}
                  onToggle={toggleExpanded}
                />
              </div>
            </div>
          )}
        </>
      ) : (
        <>
          {dragging && (
            <Global
              styles={{
                'body, :host': {
                  userSelect: 'none',
                },
              }}
            />
          )}

          <ResizablePanelHandle
            data-testid="sidebar-collapsed-strip"
            css={css(
              edgeHandleStyle,
              {
                width: theme.spacing.md,
                display: showEdgeCollapse && !isExpanded ? undefined : 'none',
              },
              alwaysVisibleBtnStyle,
            )}
          >
            <CollapseButton
              ref={expandBtnRef}
              visibility="persistent"
              className={EDGE_COLLAPSE_BTN_CLASS}
              isExpanded={false}
              onToggle={handleCollapseToggle}
              position={sidebarContext.position || 'right'}
            />
          </ResizablePanelHandle>

          <ResizableBox
            style={{
              ...resizeBoxStyle,
              ...(!isExpanded ? { display: 'none' } : {}),
            }}
            width={width || DEFAULT_WIDTH}
            height={undefined}
            axis="x"
            resizeHandles={isRight ? ['w'] : ['e']}
            minConstraints={[minWidth ?? DEFAULT_WIDTH, 150]}
            maxConstraints={[maxWidth ?? 800, 150]}
            onResizeStart={(_, { size }) => {
              onResizeStart?.(size.width);
              setDragging(true);
            }}
            onResizeStop={(_, { size }) => {
              onResizeStop?.(size.width);
              setDragging(false);
            }}
            handle={
              hideResizeHandle ? (
                <></>
              ) : (
                <ResizablePanelHandle
                  className="resizable-panel-handle"
                  css={css(
                    edgeHandleStyle,
                    {
                      width: 4,
                      position: 'absolute',
                      top: 0,
                      cursor: isRight ? 'w-resize' : 'e-resize',
                      ...resizeHandleStyle,
                    },
                    dragging && highlightedBorderStyle,
                  )}
                >
                  {showEdgeCollapse && (
                    <CollapseButton
                      ref={collapseBtnRef}
                      visibility="onHover"
                      className={EDGE_COLLAPSE_BTN_CLASS}
                      isExpanded
                      onToggle={handleCollapseToggle}
                      position={sidebarContext.position || 'right'}
                    />
                  )}
                </ResizablePanelHandle>
              )
            }
            css={[containerStyle, hiddenPanelStyle]}
            aria-hidden={isPanelClosed}
          >
            <div
              ref={ref}
              css={[
                {
                  opacity: 1,
                  animation: animation?.show,
                  direction: 'ltr',
                  height: '100%',
                },
                dangerouslyAppendEmotionCSS,
              ]}
            >
              {children}
            </div>
          </ResizableBox>
        </>
      )}
    </ContentContext.Provider>
  );
});

// ---------------------------------------------------------------------------
// Panel components
// ---------------------------------------------------------------------------

export function Panel({
  panelId,
  children,
  forceRender = false,
  dangerouslyAppendEmotionCSS,
  ...delegated
}: PanelProps): JSX.Element | null {
  const { openPanelId, destroyInactivePanels } = useContext(ContentContext);
  const hasOpenedPanelRef = useRef(false);
  const isPanelOpen = openPanelId === panelId;

  if (isPanelOpen && !hasOpenedPanelRef.current) {
    hasOpenedPanelRef.current = true;
  }

  if ((destroyInactivePanels || !hasOpenedPanelRef.current) && !isPanelOpen && !forceRender) return null;

  return (
    <div
      css={[
        { display: 'flex', height: '100%', flexDirection: 'column' },
        dangerouslyAppendEmotionCSS,
        !isPanelOpen && { display: 'none' },
      ]}
      aria-hidden={!isPanelOpen}
      {...delegated}
    >
      {children}
    </div>
  );
}

export function PanelHeader({
  children,
  dangerouslyAppendEmotionCSS,
  componentId,
  closeIcon,
}: PanelHeaderProps): JSX.Element {
  const { theme } = useDesignSystemTheme();
  const contentContext = useContext(ContentContext);
  return (
    <div
      css={[
        {
          display: 'flex',
          paddingLeft: 8,
          paddingRight: 4,
          alignItems: 'center',
          minHeight: theme.general.heightSm,
          justifyContent: 'space-between',
          fontWeight: theme.typography.typographyBoldFontWeight,
          color: theme.colors.textPrimary,
        },
        dangerouslyAppendEmotionCSS,
      ]}
    >
      <div css={{ width: contentContext.closable ? `calc(100% - ${theme.spacing.lg}px)` : '100%' }}>
        <Typography.Title
          level={4}
          css={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',

            '&&': {
              margin: 0,
            },
          }}
        >
          {children}
        </Typography.Title>
      </div>
      {contentContext.closable ? (
        <div>
          <Button
            componentId={
              componentId ? `${componentId}.close` : 'codegen_design-system_src_design-system_sidebar_sidebar.tsx_427'
            }
            size="small"
            icon={closeIcon ?? <CloseIcon />}
            aria-label="Close"
            onClick={() => {
              contentContext.setIsClosed();
            }}
          />
        </div>
      ) : null}
    </div>
  );
}

export function PanelHeaderTitle({ title, dangerouslyAppendEmotionCSS }: PanelHeaderTitleProps) {
  return (
    <div
      title={title}
      css={[
        {
          alignSelf: 'center',
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
        },
        dangerouslyAppendEmotionCSS,
      ]}
    >
      {title}
    </div>
  );
}

export function PanelHeaderButtons({ children, dangerouslyAppendEmotionCSS }: PanelHeaderButtonProps) {
  const { theme } = useDesignSystemTheme();
  return (
    <div
      css={[
        { display: 'flex', alignItems: 'center', gap: theme.spacing.xs, paddingRight: theme.spacing.xs },
        dangerouslyAppendEmotionCSS,
      ]}
    >
      {children}
    </div>
  );
}

export function PanelBody({ children, dangerouslyAppendEmotionCSS }: PanelBodyProps): JSX.Element {
  const { theme } = useDesignSystemTheme();
  const [shouldBeFocusable, setShouldBeFocusable] = useState<boolean>(false);
  const bodyRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ref = bodyRef.current;
    if (ref) {
      if (ref.scrollHeight > ref.clientHeight) {
        setShouldBeFocusable(true);
      } else {
        setShouldBeFocusable(false);
      }
    }
  }, []);

  return (
    <div
      ref={bodyRef}
      // Needed to make panel body content focusable when scrollable for keyboard-only users to be able to focus & scroll
      // eslint-disable-next-line jsx-a11y/no-noninteractive-tabindex
      tabIndex={shouldBeFocusable ? 0 : -1}
      css={[
        {
          height: '100%',
          overflowX: 'hidden',
          overflowY: 'auto',
          padding: '0 8px',
          colorScheme: theme.isDarkMode ? 'dark' : 'light',
        },
        dangerouslyAppendEmotionCSS,
      ]}
    >
      {children}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Compound component assembly
// ---------------------------------------------------------------------------

export const Sidebar = /* #__PURE__ */ (() => {
  function Sidebar({ position, children, dangerouslyAppendEmotionCSS, ...dataProps }: SidebarProps): JSX.Element {
    const { theme } = useDesignSystemTheme();

    const value = useMemo(() => {
      return {
        position: position || 'left',
      };
    }, [position]);
    return (
      <SidebarContext.Provider value={value}>
        <div
          {...addDebugOutlineIfEnabled()}
          {...dataProps}
          css={[
            {
              display: 'flex',
              height: '100%',
              backgroundColor: theme.colors.backgroundPrimary,
              flexDirection: position === 'right' ? 'row-reverse' : 'row',
              borderStyle: 'solid',
              borderColor: theme.colors.border,
              borderWidth:
                position === 'right'
                  ? `0 0 0 ${theme.general.borderWidth}px`
                  : `0px ${theme.general.borderWidth}px 0 0`,
              boxSizing: 'content-box',
              position: 'relative',
            },
            dangerouslyAppendEmotionCSS,
          ]}
        >
          {children}
        </div>
      </SidebarContext.Provider>
    );
  }

  Sidebar.Content = Content;
  Sidebar.Nav = Nav;
  Sidebar.NavButton = NavButton;
  Sidebar.Panel = Panel;
  Sidebar.PanelHeader = PanelHeader;
  Sidebar.PanelHeaderTitle = PanelHeaderTitle;
  Sidebar.PanelHeaderButtons = PanelHeaderButtons;
  Sidebar.PanelBody = PanelBody;

  return Sidebar;
})();
