import React, { forwardRef, useMemo } from 'react';

import type { CollapseButtonProps } from './types';
import { getCollapseIcon } from './utils';
import { useDesignSystemTheme } from '../Hooks/useDesignSystemTheme';

const ROUND_BUTTON_SIZE = 24;

export const CollapseButton = forwardRef<HTMLDivElement, CollapseButtonProps>(function CollapseButton(
  { isExpanded, position, onToggle, visibility = 'persistent', className, componentId },
  ref,
) {
  const { theme } = useDesignSystemTheme();
  const Icon = getCollapseIcon(position, isExpanded);
  const ariaLabel = isExpanded ? 'hide sidebar' : 'expand sidebar';

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onToggle();
    }
  };

  const positionStyle = useMemo(
    () => ({
      top: '50%',
      transform: 'translateY(-50%)',
      ...(position === 'right' ? { left: -ROUND_BUTTON_SIZE / 2 } : { right: -ROUND_BUTTON_SIZE / 2 }),
    }),
    [position],
  );

  const hiddenByDefault = visibility === 'onHover';

  return (
    <div
      ref={ref}
      className={className}
      role="button"
      tabIndex={0}
      aria-label={ariaLabel}
      aria-expanded={isExpanded}
      data-component-id={componentId}
      onClick={(e) => {
        e.stopPropagation();
        onToggle();
      }}
      onKeyDown={handleKeyDown}
      css={{
        position: 'absolute',
        ...positionStyle,
        zIndex: theme.options.zIndexBase - 1,
        width: ROUND_BUTTON_SIZE,
        height: ROUND_BUTTON_SIZE,
        borderRadius: '50%',
        background: theme.colors.backgroundPrimary,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        cursor: 'pointer',
        boxShadow: `0 0 0 1px ${theme.colors.border}`,
        outline: 'none',
        ...(hiddenByDefault && {
          opacity: 0,
          pointerEvents: 'none' as const,
        }),
        '&:hover': {
          opacity: 1,
          pointerEvents: 'auto',
          boxShadow: `0 0 0 2px ${theme.colors.actionDefaultBorderHover}`,
        },
        '&:focus-visible': {
          opacity: 1,
          pointerEvents: 'auto',
          boxShadow: `0 0 0 2px ${theme.colors.actionDefaultBorderFocus}`,
        },
      }}
    >
      <Icon css={{ fontSize: ROUND_BUTTON_SIZE * 0.75, color: theme.colors.textSecondary }} />
    </div>
  );
});
